import React, { useState } from 'react';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

const WORKFLOWS = [
  { id: 'market_analysis', name: 'Market Analysis', description: 'Run comprehensive market analysis for a city' },
  { id: 'lead_followup', name: 'Lead Follow-up', description: 'Follow up with leads after initial contact' },
  { id: 'new_listing', name: 'New Listing', description: 'Process and publish a new property listing' }
];

function Workflows() {
  const [selectedWorkflow, setSelectedWorkflow] = useState('');
  const [location, setLocation] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedWorkflow) return;

    setLoading(true);
    try {
      const response = await fetch(`${API_URL}/ai_chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          message: selectedWorkflow === 'market_analysis' 
            ? `Give me a real estate market analysis for ${location || 'Austin TX'}`
            : selectedWorkflow === 'lead_followup'
            ? `Write a professional lead follow-up email for ${location || 'a potential buyer'}`
            : `Create a new listing description for property at ${location || '123 Main St'}`
        })
      });
      const data = await response.json();
      setResult(data.response || data);
    } catch (error) {
      setResult({ error: error.message });
    }
    setLoading(false);
  };

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto' }}>
      <h2>⚙️ Workflow Automation</h2>

      <form onSubmit={handleSubmit} style={{ 
        background: 'rgba(22,27,34,0.8)', 
        border: '1px solid rgba(139,148,158,0.15)', 
        borderRadius: '16px', 
        padding: '2rem',
        marginBottom: '1.5rem'
      }}>
        <div className="form-group">
          <label>Select Workflow</label>
          <select 
            value={selectedWorkflow} 
            onChange={(e) => setSelectedWorkflow(e.target.value)}
            style={{
              width: '100%',
              padding: '0.875rem 1rem',
              background: 'rgba(0,0,0,0.4)',
              border: '1px solid rgba(139,148,158,0.25)',
              borderRadius: '10px',
              color: '#fff',
              fontSize: '0.9rem'
            }}
          >
            <option value="">-- Select --</option>
            {WORKFLOWS.map(w => (
              <option key={w.id} value={w.id}>{w.name}</option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label>Location / Details</label>
          <input 
            type="text"
            value={location}
            onChange={(e) => setLocation(e.target.value)}
            placeholder={selectedWorkflow === 'market_analysis' ? 'Austin TX' : 'Lead name or property address'}
            style={{
              width: '100%',
              padding: '0.875rem 1rem',
              background: 'rgba(0,0,0,0.4)',
              border: '1px solid rgba(139,148,158,0.25)',
              borderRadius: '10px',
              color: '#fff',
              fontSize: '0.9rem'
            }}
          />
        </div>

        <button 
          type="submit" 
          disabled={!selectedWorkflow || loading}
          style={{
            background: 'linear-gradient(135deg, #238636 0%, #2ea043 100%)',
            color: 'white',
            border: 'none',
            padding: '0.875rem 2rem',
            borderRadius: '10px',
            fontWeight: '600',
            cursor: 'pointer',
            width: '100%'
          }}
        >
          {loading ? 'Running...' : 'Run Workflow'}
        </button>
      </form>

      {result && (
        <div style={{ 
          background: 'rgba(0,0,0,0.3)', 
          borderRadius: '12px', 
          padding: '1.5rem',
          textAlign: 'left'
        }}>
          <h3 style={{ color: '#e6edf3', marginBottom: '1rem' }}>Results:</h3>
          <pre style={{ 
            whiteSpace: 'pre-wrap', 
            color: '#e6edf3',
            fontSize: '0.9rem',
            fontFamily: 'inherit'
          }}>
            {typeof result === 'string' ? result : JSON.stringify(result, null, 2)}
          </pre>
        </div>
      )}
    </div>
  );
}

export default Workflows;
